import{_ as t,o as a,c as s,ag as n}from"./chunks/framework.6MCaaFDc.js";const h=JSON.parse('{"title":"Software Engineering","description":"","frontmatter":{},"headers":[],"relativePath":"theory/programming/software-engineering.md","filePath":"theory/programming/software-engineering.md"}'),r={name:"theory/programming/software-engineering.md"};function i(o,e,l,d,p,g){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="software-engineering" tabindex="-1">Software Engineering <a class="header-anchor" href="#software-engineering" aria-label="Permalink to &quot;Software Engineering&quot;">​</a></h1><p>Building a small program is straightforward. Building software used by millions of people, that must be maintained for decades, that must be secure, fast, and correct — that requires engineering. Software engineering applies systematic, disciplined approaches to developing software.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 12</p><p>Software engineering methodologies (Waterfall, Agile, RAD) are primarily Grade 12 content, linked to PAT preparation.</p></div><hr><h2 id="what-is-software-engineering" tabindex="-1">What is Software Engineering? <a class="header-anchor" href="#what-is-software-engineering" aria-label="Permalink to &quot;What is Software Engineering?&quot;">​</a></h2><p><strong>Software engineering</strong> is the application of engineering principles to the design, development, testing, and maintenance of software systems.</p><p>It addresses:</p><ul><li>How to organise large development teams</li><li>How to manage changing requirements</li><li>How to ensure quality at scale</li><li>How to deliver on time and budget</li></ul><hr><h2 id="the-software-development-life-cycle-sdlc" tabindex="-1">The Software Development Life Cycle (SDLC) <a class="header-anchor" href="#the-software-development-life-cycle-sdlc" aria-label="Permalink to &quot;The Software Development Life Cycle (SDLC)&quot;">​</a></h2><p>The <strong>SDLC</strong> is the structured process for planning, creating, testing, and deploying software.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Requirements analysis</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>2. System design</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>3. Implementation (coding)</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>4. Testing</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>5. Deployment</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>6. Maintenance</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h3 id="phase-details" tabindex="-1">Phase Details <a class="header-anchor" href="#phase-details" aria-label="Permalink to &quot;Phase Details&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Phase</th><th>Activities</th><th>Output</th></tr></thead><tbody><tr><td><strong>Requirements</strong></td><td>Gather user needs; document what system must do</td><td>Requirements specification</td></tr><tr><td><strong>Design</strong></td><td>Architecture, database design, interface design</td><td>Design documents, ERDs</td></tr><tr><td><strong>Implementation</strong></td><td>Write code</td><td>Source code</td></tr><tr><td><strong>Testing</strong></td><td>Find and fix errors; verify requirements met</td><td>Test results, bug reports</td></tr><tr><td><strong>Deployment</strong></td><td>Install and release to users</td><td>Running system</td></tr><tr><td><strong>Maintenance</strong></td><td>Fix bugs, add features, improve performance</td><td>Updated software</td></tr></tbody></table><hr><h2 id="development-methodologies" tabindex="-1">Development Methodologies <a class="header-anchor" href="#development-methodologies" aria-label="Permalink to &quot;Development Methodologies&quot;">​</a></h2><p>A <strong>methodology</strong> is a structured approach to software development — it defines who does what, when, and how.</p><hr><h2 id="waterfall-model" tabindex="-1">Waterfall Model <a class="header-anchor" href="#waterfall-model" aria-label="Permalink to &quot;Waterfall Model&quot;">​</a></h2><p>The <strong>Waterfall model</strong> is a sequential, linear development process — each phase must be complete before the next begins.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Requirements → Design → Implementation → Testing → Deployment → Maintenance</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>No going back — like water falling; once you&#39;ve passed a phase, you don&#39;t return.</p><h3 id="advantages-of-waterfall" tabindex="-1">Advantages of Waterfall <a class="header-anchor" href="#advantages-of-waterfall" aria-label="Permalink to &quot;Advantages of Waterfall&quot;">​</a></h3><ul><li>Simple and easy to understand</li><li>Clear milestones and deliverables</li><li>Good documentation — each phase has defined outputs</li><li>Works well when requirements are clear and fixed</li><li>Easy to manage — clear phase progression</li></ul><h3 id="disadvantages-of-waterfall" tabindex="-1">Disadvantages of Waterfall <a class="header-anchor" href="#disadvantages-of-waterfall" aria-label="Permalink to &quot;Disadvantages of Waterfall&quot;">​</a></h3><ul><li>Very rigid — difficult to accommodate changing requirements</li><li>Testing happens late — bugs found at the end are expensive to fix</li><li>Client sees no working software until near the end</li><li>High risk — if design is wrong, everything built on it is wrong</li><li>Poor for complex, long-term projects where requirements change</li></ul><h3 id="when-to-use-waterfall" tabindex="-1">When to use Waterfall: <a class="header-anchor" href="#when-to-use-waterfall" aria-label="Permalink to &quot;When to use Waterfall:&quot;">​</a></h3><ul><li>Small, well-defined projects</li><li>Requirements are completely clear and unlikely to change</li><li>Regulated industries (medical devices, aerospace) requiring documentation</li></ul><hr><h2 id="agile-methodology" tabindex="-1">Agile Methodology <a class="header-anchor" href="#agile-methodology" aria-label="Permalink to &quot;Agile Methodology&quot;">​</a></h2><p><strong>Agile</strong> is an iterative, flexible approach where software is developed in short cycles called <strong>sprints</strong> (usually 1–4 weeks).</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Plan → Design → Build → Test → Review → (repeat)</span></span>
<span class="line"><span>         ↑________________________________↓</span></span>
<span class="line"><span>                  Sprint cycle</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>After each sprint, a working piece of software is delivered and reviewed. Requirements can change between sprints.</p><p><strong>Agile values (Agile Manifesto):</strong></p><ul><li><strong>Individuals and interactions</strong> over processes and tools</li><li><strong>Working software</strong> over comprehensive documentation</li><li><strong>Customer collaboration</strong> over contract negotiation</li><li><strong>Responding to change</strong> over following a plan</li></ul><h3 id="advantages-of-agile" tabindex="-1">Advantages of Agile <a class="header-anchor" href="#advantages-of-agile" aria-label="Permalink to &quot;Advantages of Agile&quot;">​</a></h3><ul><li>Flexible — requirements can change throughout development</li><li>Client sees working software frequently (after each sprint)</li><li>Bugs found early — testing in every sprint</li><li>High client satisfaction — continuous collaboration</li><li>Reduced risk — problems identified early</li></ul><h3 id="disadvantages-of-agile" tabindex="-1">Disadvantages of Agile <a class="header-anchor" href="#disadvantages-of-agile" aria-label="Permalink to &quot;Disadvantages of Agile&quot;">​</a></h3><ul><li>Less predictable — hard to estimate total cost and time upfront</li><li>Requires constant client involvement</li><li>Less documentation — can be problematic for maintenance</li><li>Can lose sight of overall architecture</li><li>Not suitable for fixed-scope contracts</li></ul><h3 id="scrum-agile-framework" tabindex="-1">Scrum (Agile Framework) <a class="header-anchor" href="#scrum-agile-framework" aria-label="Permalink to &quot;Scrum (Agile Framework)&quot;">​</a></h3><p><strong>Scrum</strong> is the most popular Agile framework:</p><ul><li><strong>Product backlog</strong> — prioritised list of all features</li><li><strong>Sprint backlog</strong> — tasks committed to for this sprint</li><li><strong>Daily standup</strong> — 15-minute team meeting</li><li><strong>Sprint review</strong> — demo working software to stakeholders</li><li><strong>Sprint retrospective</strong> — team reflects on how to improve</li></ul><p><strong>Scrum roles:</strong></p><ul><li><strong>Product Owner</strong> — represents client; prioritises features</li><li><strong>Scrum Master</strong> — facilitates process; removes obstacles</li><li><strong>Development Team</strong> — builds the software</li></ul><hr><h2 id="rad-—-rapid-application-development" tabindex="-1">RAD — Rapid Application Development <a class="header-anchor" href="#rad-—-rapid-application-development" aria-label="Permalink to &quot;RAD — Rapid Application Development&quot;">​</a></h2><p><strong>RAD</strong> is a methodology focused on delivering software quickly through:</p><ul><li>Prototyping — build rough working versions early</li><li>Heavy user involvement in prototype review</li><li>Iterative refinement until final product</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Requirements planning → User design → Rapid construction → Cutover</span></span>
<span class="line"><span>       ↑________________________↓</span></span>
<span class="line"><span>           Prototype cycles</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="advantages-of-rad" tabindex="-1">Advantages of RAD <a class="header-anchor" href="#advantages-of-rad" aria-label="Permalink to &quot;Advantages of RAD&quot;">​</a></h3><ul><li>Very fast development</li><li>Users see and interact with prototypes early</li><li>Reduced risk — problems caught during prototyping</li><li>Good for projects where speed is critical</li></ul><h3 id="disadvantages-of-rad" tabindex="-1">Disadvantages of RAD <a class="header-anchor" href="#disadvantages-of-rad" aria-label="Permalink to &quot;Disadvantages of RAD&quot;">​</a></h3><ul><li>Requires committed, available users throughout</li><li>Not suitable for large teams</li><li>Performance issues may be overlooked in rush to deliver</li><li>Poor for complex system integrations</li></ul><hr><h2 id="methodology-comparison" tabindex="-1">Methodology Comparison <a class="header-anchor" href="#methodology-comparison" aria-label="Permalink to &quot;Methodology Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Waterfall</th><th>Agile</th><th>RAD</th></tr></thead><tbody><tr><td>Approach</td><td>Sequential</td><td>Iterative</td><td>Prototype-based</td></tr><tr><td>Flexibility</td><td>Low</td><td>High</td><td>Medium</td></tr><tr><td>Client involvement</td><td>At start and end</td><td>Continuous</td><td>Continuous</td></tr><tr><td>Testing</td><td>End of project</td><td>Every sprint</td><td>During prototyping</td></tr><tr><td>Documentation</td><td>Extensive</td><td>Minimal</td><td>Moderate</td></tr><tr><td>Suitable for</td><td>Fixed, clear requirements</td><td>Changing requirements</td><td>Fast delivery</td></tr><tr><td>Risk</td><td>High (late testing)</td><td>Low (early feedback)</td><td>Medium</td></tr><tr><td>Team size</td><td>Any</td><td>Small-medium</td><td>Small</td></tr></tbody></table><hr><h2 id="software-quality-attributes" tabindex="-1">Software Quality Attributes <a class="header-anchor" href="#software-quality-attributes" aria-label="Permalink to &quot;Software Quality Attributes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Attribute</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>Correctness</strong></td><td>Does what it&#39;s supposed to do</td></tr><tr><td><strong>Reliability</strong></td><td>Works consistently without failure</td></tr><tr><td><strong>Efficiency</strong></td><td>Uses minimal resources (CPU, memory)</td></tr><tr><td><strong>Maintainability</strong></td><td>Easy to update and modify</td></tr><tr><td><strong>Usability</strong></td><td>Easy for users to learn and use</td></tr><tr><td><strong>Portability</strong></td><td>Works on different platforms</td></tr><tr><td><strong>Security</strong></td><td>Protected against attacks and unauthorised access</td></tr><tr><td><strong>Scalability</strong></td><td>Handles increased load without performance loss</td></tr></tbody></table><hr><h2 id="pat-—-practical-assessment-task" tabindex="-1">PAT — Practical Assessment Task <a class="header-anchor" href="#pat-—-practical-assessment-task" aria-label="Permalink to &quot;PAT — Practical Assessment Task&quot;">​</a></h2><p>The <strong>PAT</strong> is a major component of Grade 12 IT assessment (25% of final mark).</p><p><strong>PAT phases:</strong></p><table tabindex="0"><thead><tr><th>Phase</th><th>What it covers</th></tr></thead><tbody><tr><td><strong>Phase 1</strong></td><td>Requirements, system design (ERDs, class diagrams, interface design)</td></tr><tr><td><strong>Phase 2</strong></td><td>Coding — implement the designed system in Delphi</td></tr><tr><td><strong>Phase 3</strong></td><td>Testing — test plans, test results, evidence of testing</td></tr></tbody></table><p><strong>Documentation required:</strong></p><ul><li>Project plan with milestones</li><li>System requirements specification</li><li>ERD and database design</li><li>Class diagrams (OOP)</li><li>Interface mockups</li><li>Source code</li><li>Test plan with test data</li><li>Test results</li></ul><p><strong>PAT relates to:</strong></p><ul><li>Software engineering (design documentation)</li><li>OOP (class design)</li><li>Database design (ERD, normalisation)</li><li>SQL (queries in Delphi)</li><li>Algorithms (problem-solving)</li></ul><hr><h2 id="version-control" tabindex="-1">Version Control <a class="header-anchor" href="#version-control" aria-label="Permalink to &quot;Version Control&quot;">​</a></h2><p><strong>Version control</strong> systems track changes to code over time, allowing teams to collaborate and revert to earlier versions.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Benefit</th></tr></thead><tbody><tr><td><strong>History</strong></td><td>See every change ever made and who made it</td></tr><tr><td><strong>Branching</strong></td><td>Work on features in isolation; merge when ready</td></tr><tr><td><strong>Rollback</strong></td><td>Revert to any previous version</td></tr><tr><td><strong>Collaboration</strong></td><td>Multiple developers work on the same codebase</td></tr></tbody></table><p><strong>Git</strong> is the most widely used version control system.<br><strong>GitHub</strong> is a hosting platform for Git repositories.</p><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>SDLC</strong></td><td>Software Development Life Cycle — structured software development process</td></tr><tr><td><strong>Waterfall</strong></td><td>Sequential development methodology — one phase at a time</td></tr><tr><td><strong>Agile</strong></td><td>Iterative methodology delivering working software in short sprints</td></tr><tr><td><strong>Sprint</strong></td><td>Short development cycle (1–4 weeks) in Agile</td></tr><tr><td><strong>RAD</strong></td><td>Rapid Application Development — fast prototyping-based methodology</td></tr><tr><td><strong>Prototype</strong></td><td>Early working version of software for feedback</td></tr><tr><td><strong>Scrum</strong></td><td>Popular Agile framework with sprints and specific roles</td></tr><tr><td><strong>PAT</strong></td><td>Practical Assessment Task — Grade 12 major project</td></tr><tr><td><strong>Version control</strong></td><td>System tracking changes to code over time</td></tr><tr><td><strong>Maintenance</strong></td><td>Ongoing updates, bug fixes, and improvements after deployment</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;Compare Waterfall and Agile methodologies — give TWO advantages of each&quot;</strong> — Waterfall: clear documentation, simple management, good for fixed requirements; Agile: flexible to changing requirements, client sees working software frequently, bugs found early</p></li><li><p><strong>&quot;Give TWO disadvantages of the Waterfall model&quot;</strong> — very rigid, difficult to change requirements; testing only at the end means bugs discovered late (expensive); client sees no working software until near the end</p></li><li><p><strong>&quot;What is a sprint in Agile? How long is it typically?&quot;</strong> — A short development cycle delivering a working piece of software; typically 1–4 weeks</p></li><li><p><strong>&quot;Give THREE phases of the SDLC&quot;</strong> — requirements analysis; design; implementation; testing; deployment; maintenance</p></li><li><p><strong>&quot;Why is Agile more suitable than Waterfall for a project where client requirements may change frequently?&quot;</strong> — Agile accommodates changing requirements between sprints; clients are involved throughout; working software delivered after each sprint so changes can be incorporated; Waterfall requires fixed requirements from the start</p></li></ol></div>`,79)])])}const u=t(r,[["render",i]]);export{h as __pageData,u as default};
